// // This module counts down on each positive clock edge and resets to 15 when the reset signal is low.
module binary_counter (
    input wire clk,
    input wire rst,
    output reg [3:0] count
    );

always @(posedge clk) begin
    if (rst)
        count <= 4'b0000;
    else
        count <= count + 1;
end

endmodule
